import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableTimes, setAvailableTimes] = useState([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  const [popup, setPopup] = useState({ show: false, message: "" });

  // ================= DOCTOR =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableTimes(data.doctor.available_time_slots || []);
      });
  }, [doctor_id]);

  // ================= FEEDBACK =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data));
  }, [doctor_id]);

  const avgRating =
    feedbacks.length > 0
      ? (
          feedbacks.reduce((s, f) => s + f.rating, 0) / feedbacks.length
        ).toFixed(1)
      : 0;

  // ================= BOOK =================
  const handleBook = async () => {
    if (!date || !time) {
      setPopup({ show: true, message: "Please select date and time" });
      return;
    }

    const token = localStorage.getItem("token");
    if (!token) return navigate("/login");

    try {
      const res = await fetch("http://127.0.0.1:8000/book-appointment/", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Token ${token}`,
        },
        body: JSON.stringify({
          doctor_id,
          appointment_date: date,
          time_slot: time,
        }),
      });

      const data = await res.json();

      if (res.ok) {
        setPopup({ show: true, message: "Appointment booked successfully!" });
        setTimeout(() => navigate("/myappointments"), 1500);
      } else {
        setPopup({ show: true, message: data.error || "Booking failed" });
      }
    } catch {
      setPopup({ show: true, message: "Server error" });
    }
  };

  // ================= FEEDBACK =================
  const submitFeedback = () => {
    if (!rating || !comment) {
      setPopup({ show: true, message: "Please add rating and comment" });
      return;
    }

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
      });
  };

  if (!doctor)
    return <h2 style={{ textAlign: "center", marginTop: 50 }}>Loading...</h2>;

  return (
    <div style={styles.page}>
      <Navbar />

      {/* POPUP */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.modal}>
            <p>{popup.message}</p>
            <button onClick={() => setPopup({ show: false })} style={styles.btn}>
              OK
            </button>
          </div>
        </div>
      )}

      {/* PROFILE */}
      <div style={styles.container}>
        <div style={styles.card}>
          
          {/* IMAGE */}
          <img
            src={doctor.image || "https://cdn-icons-png.flaticon.com/512/387/387561.png"}
            alt={doctor.name}
            style={styles.img}
          />

          {/* DETAILS */}
          <h2>{doctor.name}</h2>

          <div style={styles.info}>
            <p><b>Gender:</b> {doctor.gender}</p>
            <p><b>Specialization:</b> {doctor.field}</p>
            <p><b>Experience:</b> {doctor.experience} years</p>
            <p><b>Qualification:</b> {doctor.qualification}</p>
          </div>

          {/* BOOKING */}
          <div style={styles.box}>
            <input type="date" onChange={(e) => setDate(e.target.value)} style={styles.input} />

            <select onChange={(e) => setTime(e.target.value)} style={styles.input}>
              <option value="">Select Time</option>
              {availableTimes.map((t, i) => (
                <option key={i}>{t}</option>
              ))}
            </select>

            <button onClick={handleBook} style={styles.bookBtn}>
              Book Appointment
            </button>
          </div>

          {/* FEEDBACK */}
          <div style={styles.feedback}>
            <h3>Reviews ⭐ {avgRating}</h3>

            <select onChange={(e) => setRating(e.target.value)} style={styles.input}>
              <option value="">Rating</option>
              <option value="5">⭐⭐⭐⭐⭐</option>
              <option value="4">⭐⭐⭐⭐</option>
              <option value="3">⭐⭐⭐</option>
              <option value="2">⭐⭐</option>
              <option value="1">⭐</option>
            </select>

            <textarea
              placeholder="Write feedback..."
              value={comment}
              onChange={(e) => setComment(e.target.value)}
              style={styles.textarea}
            />

            <button onClick={submitFeedback} style={styles.feedbackBtn}>
              Submit Review
            </button>

            {feedbacks.map((f, i) => (
              <div key={i} style={styles.review}>
                <b>{f.user_name}</b>
                <p>{"⭐".repeat(f.rating)}</p>
                <p>{f.comment}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* ================= STYLES ================= */
const styles = {
  page: { background: "#f4f6f9", minHeight: "100vh" },

  container: { display: "flex", justifyContent: "center", padding: 30 },

  card: {
    width: "60%",
    background: "#fff",
    padding: 30,
    borderRadius: 12,
    textAlign: "center",
    boxShadow: "0 6px 20px rgba(0,0,0,0.08)",
  },

  img: {
    width: 140,
    height: 140,
    borderRadius: "50%",
    objectFit: "cover",
  },

  info: {
    textAlign: "left",
    marginTop: 15,
  },

  box: {
    marginTop: 20,
  },

  input: {
    width: "100%",
    padding: 10,
    margin: "8px 0",
    borderRadius: 8,
    border: "1px solid #ddd",
  },

  textarea: {
    width: "100%",
    height: 70,
    padding: 10,
    borderRadius: 8,
    border: "1px solid #ddd",
  },

  bookBtn: {
    width: "100%",
    padding: 10,
    background: "#2c3e50",
    color: "#fff",
    border: "none",
    borderRadius: 8,
  },

  feedback: {
    marginTop: 20,
    textAlign: "left",
  },

  feedbackBtn: {
    width: "100%",
    padding: 10,
    background: "#27ae60",
    color: "#fff",
    border: "none",
    borderRadius: 8,
    marginTop: 8,
  },

  review: {
    background: "#f9fafb",
    padding: 10,
    borderRadius: 8,
    marginTop: 10,
  },

  overlay: {
    position: "fixed",
    top: 0,
    left: 0,
    background: "rgba(0,0,0,0.5)",
    width: "100%",
    height: "100%",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  modal: {
    background: "#fff",
    padding: 20,
    borderRadius: 10,
    textAlign: "center",
  },

  btn: {
    marginTop: 10,
    padding: "6px 15px",
    background: "#2c3e50",
    color: "#fff",
    border: "none",
    borderRadius: 6,
  },
};
